#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-16

# =============================================================================
# Skill token scorecard
# =============================================================================
# Pairs with CC 2.1.111's /skills menu sort-by-token-count (press `t`). Lists
# every SKILL.md ranked by estimated token count. Flags any skill exceeding
# the soft ceiling (default 8k tokens, per skill-authoring.md guidance).
#
# Estimation: bytes/4 — the canonical rough ratio Anthropic documents for
# English text. Good enough for ranking; off by ±10-20% from the actual
# tokenizer but consistent within the scorecard.
#
# Advisory by default. Set SKILL_TOKEN_ENFORCE=1 to fail the run if any
# skill exceeds the ceiling.
# =============================================================================

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"
SKILLS_DIR="$REPO_ROOT/src/skills"
BASELINE_FILE="$SCRIPT_DIR/.skill-tokens-baseline.json"

RED='\033[0;31m'; GREEN='\033[0;32m'; YELLOW='\033[1;33m'
BLUE='\033[0;34m'; BOLD='\033[1m'; NC='\033[0m'

CEILING_TOKENS="${SKILL_TOKEN_CEILING:-8000}"
TOP_N="${SKILL_TOKEN_TOP_N:-15}"
ENFORCE="${SKILL_TOKEN_ENFORCE:-0}"

echo -e "${BLUE}${BOLD}Skill token scorecard${NC}"
echo -e "  Ceiling:  ${CEILING_TOKENS} tokens"
echo -e "  Top N:    ${TOP_N}"
echo -e "  Mode:     $([[ "$ENFORCE" == "1" ]] && echo "ENFORCE" || echo "advisory")"
echo ""

scores=()
offenders=()

while IFS= read -r -d '' skill_md; do
    skill_name="$(basename "$(dirname "$skill_md")")"
    bytes="$(wc -c < "$skill_md" | tr -d ' ')"
    [[ "$bytes" -eq 0 ]] && continue
    tokens=$(( bytes / 4 ))

    scores+=("$(printf '%8d %s' "$tokens" "$skill_name")")

    if [[ "$tokens" -gt "$CEILING_TOKENS" ]]; then
        offenders+=("$(printf '%s (%d tokens)' "$skill_name" "$tokens")")
    fi
done < <(find "$SKILLS_DIR" -name SKILL.md -print0 | sort -z)

total_skills="${#scores[@]}"
echo -e "${BOLD}Top ${TOP_N} skills by estimated token count (of ${total_skills} total):${NC}"
printf '%s\n' "${scores[@]}" | sort -nr | head -"$TOP_N" | while IFS= read -r row; do
    tokens="$(echo "$row" | awk '{print $1}')"
    name="$(echo "$row" | awk '{print $2}')"
    if [[ "$tokens" -gt "$CEILING_TOKENS" ]]; then
        echo -e "  ${YELLOW}$(printf '%8d  %s  ⚠' "$tokens" "$name")${NC}"
    else
        echo -e "  $(printf '%8d  %s' "$tokens" "$name")"
    fi
done
echo ""

if [[ ${#offenders[@]} -eq 0 ]]; then
    echo -e "${GREEN}✓ All skills under ${CEILING_TOKENS}-token ceiling${NC}"
else
    echo -e "${YELLOW}⚠ ${#offenders[@]} skill(s) above ${CEILING_TOKENS} tokens:${NC}"
    printf '  - %s\n' "${offenders[@]}"
fi
echo ""

# Always write baseline snapshot (informational)
{
    echo "{"
    echo "  \"generated_at\": \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\","
    echo "  \"ceiling_tokens\": $CEILING_TOKENS,"
    echo "  \"skill_count\": $total_skills,"
    echo "  \"offender_count\": ${#offenders[@]},"
    echo "  \"offenders\": ["
    for i in "${!offenders[@]}"; do
        comma=","; [[ $i -eq $((${#offenders[@]} - 1)) ]] && comma=""
        echo "    \"${offenders[$i]}\"$comma"
    done
    echo "  ]"
    echo "}"
} > "$BASELINE_FILE"

if [[ "$ENFORCE" == "1" && ${#offenders[@]} -gt 0 ]]; then
    echo -e "${RED}✗ Enforcement enabled — failing due to bloated skills.${NC}"
    exit 1
fi

exit 0
